import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjSunburst } from "./OjSunburst";
export { OjSunburst };

/**
 * Create an instance of [[OjSunburst]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojSunburst(driver, By.id('my-oj-sunburst'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojSunburst(driver: DriverLike, by: By): Promise<OjSunburst> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjSunburst
  if (!(webEl instanceof OjSunburst)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-sunburst>`);
  }
  return webEl;
}

register("oj-sunburst", OjSunburst);
